3	// routinglint_test.go: AST guard ensuring ResolveRoute is not called from
4	// execution-path functions in agent_cmd.go. Fails if someone re-introduces
5	// a ResolveRoute call inside newAgentRunCommand or newAgentExecuteLoopCommand
6	// (CONTRACT-003 / ddx-da19756a).
7	
8	import (
9		"go/ast"
10		"go/parser"
11		"go/token"
12		"path/filepath"
13		"testing"
14	)
15	
16	// routinglintExecutionFunctions are the CLI entry points that must NOT call
17	// ResolveRoute. These are the "run/try/work" execution paths described in
18	// the bead contract.
19	var routinglintExecutionFunctions = []string{
20		"newAgentRunCommand",
21		"newAgentExecuteLoopCommand",
22	}
23	
24	// TestRoutinglintNoResolveRouteInExecutionPaths verifies that execution-path
25	// functions in agent_cmd.go do not call .ResolveRoute(). Status/debug
26	// surfaces (newAgentCatalogCommand, newAgentRouteStatusCommand, etc.) are
27	// allowed to call ResolveRoute and are not scanned by this lint.
28	func TestRoutinglintNoResolveRouteInExecutionPaths(t *testing.T) {
29		fset := token.NewFileSet()
30		f, err := parser.ParseFile(fset, "agent_cmd.go", nil, 0)
31		if err != nil {
32			t.Fatalf("routinglint: parse agent_cmd.go: %v", err)
33		}
34	
35		bannedSet := make(map[string]bool, len(routinglintExecutionFunctions))
36		for _, name := range routinglintExecutionFunctions {
37			bannedSet[name] = true
38		}
39	
40		for _, decl := range f.Decls {
41			fn, ok := decl.(*ast.FuncDecl)
42			if !ok {
43				continue
44			}
45			if !bannedSet[fn.Name.Name] {
46				continue
47			}
48			ast.Inspect(fn.Body, func(n ast.Node) bool {
49				call, ok := n.(*ast.CallExpr)
50				if !ok {
51					return true
52				}
53				sel, ok := call.Fun.(*ast.SelectorExpr)
54				if !ok {
55					return true
56				}
57				if sel.Sel.Name == "ResolveRoute" {
58					t.Errorf("routinglint: %s calls .ResolveRoute() at %s — execution paths must pass operator constraints to Execute, not pre-resolve routes (CONTRACT-003 / ddx-da19756a)",
59						fn.Name.Name, fset.Position(call.Pos()))
60				}

